  shot_plan: [],
  brand_integration_notes: 'Keep the product readable and central in a believable lifestyle environment.',
  caption_angle: 'A small routine detail that makes the whole morning feel premium.'
};
const merged = { ...fallback, ...parsed };
merged.duration_seconds = Number.isFinite(Number(merged.duration_seconds)) ? Math.max(2, Math.min(8, Number(merged.duration_seconds))) : 4;
merged.shot_plan = Array.isArray(merged.shot_plan) ? merged.shot_plan : [];
merged.parse_ok = !!extractJson(raw);
