const downloadUrl = `http://1.34.114.64:62205/view?filename=${filename}&subfolder=${subfolder}&type=${type}&token=092475c6eb5141de21d222d375448c29cdd73c24db753dc2250c5664c3fcbb67`;
return [{ json: { prompt_id: promptId, status, ready: true, render_backend: $('Build Render Payload').item.json.render_backend, filename: file.filename, subfolder: file.subfolder || '', type: file.type || 'output', download_url: downloadUrl, brief: $('Build Render Payload').item.json } }];
